const fs = require('fs');
const CONFIG_PATH = '/home/node/.n8n/marketer/config/config.json';
const PROMPTS_PATH = '/home/node/.n8n/marketer/config/prompts.json';
const DRAFTS_PATH = '/home/node/.n8n/marketer/data/drafts.json';
const config = JSON.parse(fs.readFileSync(CONFIG_PATH, 'utf8'));
const prompts = JSON.parse(fs.readFileSync(PROMPTS_PATH, 'utf8'));
const drafts = JSON.parse(fs.readFileSync(DRAFTS_PATH, 'utf8'));
return [{ json: { config, prompts, drafts, paths: { config: CONFIG_PATH, prompts: PROMPTS_PATH, drafts: DRAFTS_PATH } } }];

const { config, prompts, drafts } = $input.first().json;
const rotation = config.contentRotation;
const lastType = drafts.lastContentType;
const available = rotation.filter(t => t !== lastType);
const picked = available[Math.floor(Math.random() * available.length)];
const typeConfig = prompts.contentTypes[picked];
const projectList = config.profile.projects.map(p => `${p.name}: ${p.description}`).join('\n');
const recentTopics = drafts.recentTopics.slice(-5).join(', ') || 'none yet';
let prompt = prompts.generatePrompt;
prompt = prompt.replace('{{contentType}}', picked);
prompt = prompt.replace('{{typeInstruction}}', typeConfig.instruction);
prompt = prompt.replace('{{typeExamples}}', typeConfig.examples.join('\n'));
prompt = prompt.replace('{{linkedinRules}}', prompts.platformRules.linkedin.instruction);
prompt = prompt.replace('{{xRules}}', prompts.platformRules.x.instruction);
prompt = prompt.replace('{{stack}}', config.profile.stack.join(', '));
prompt = prompt.replace('{{projects}}', projectList);
prompt = prompt.replace('{{tone}}', config.profile.tone);
prompt = prompt.replace('{{niche}}', config.profile.niche);
prompt = prompt.replace('{{recentTopics}}', recentTopics);
return [{ json: { prompt, systemPrompt: prompts.system, contentType: picked } }];

const fs = require('fs');
const DRAFTS_PATH = '/home/node/.n8n/marketer/data/drafts.json';
const drafts = JSON.parse(fs.readFileSync(DRAFTS_PATH, 'utf8'));
const geminiResponse = $input.first().json;
const rawText = geminiResponse.candidates[0].content.parts[0].text;
const content = JSON.parse(rawText);
const allItems = $('Pick Type & Build Prompt').first().json;
const contentType = allItems.contentType;
const now = new Date();
const dateStr = now.toISOString().split('T')[0];
const draftCount = drafts.drafts.filter(d => d.id.startsWith(dateStr)).length + 1;
const draftId = `${dateStr}-${String(draftCount).padStart(3, '0')}`;
const draft = {
  id: draftId,
  contentType: contentType,
  topic: content.topic,
  linkedin: { text: content.linkedin },
  x: content.x,
  status: 'pending',
  createdAt: now.toISOString(),
  publishedAt: null,
  postUrls: { linkedin: null, x: null }
};
drafts.drafts.push(draft);
drafts.lastContentType = contentType;
drafts.recentTopics.push(content.topic);
if (drafts.recentTopics.length > 10) {
  drafts.recentTopics = drafts.recentTopics.slice(-10);
}
fs.writeFileSync(DRAFTS_PATH, JSON.stringify(drafts, null, 2));
return [{ json: { draft } }];

const draft = $input.first().json.draft;
const REVIEW_BASE = $env.MARKETER_REVIEW_WEBHOOK || 'https://YOUR_N8N_DOMAIN/webhook/marketer-review';
const DISCORD_WEBHOOK = $env.MARKETER_DISCORD_WEBHOOK || 'https://discord.com/api/webhooks/YOUR_WEBHOOK';
const approveUrl = `${REVIEW_BASE}?action=approve&id=${draft.id}`;
const rejectUrl = `${REVIEW_BASE}?action=reject&id=${draft.id}`;
const typeLabels = {
  tech_tip: 'Tech Tip',
  building_in_public: 'Building in Public',
  thought_leadership: 'Thought Leadership',
  engagement: 'Engagement',
  curated: 'Curated'
};
const xText = draft.x.isThread
  ? draft.x.threadParts.map((t, i) => `**${i + 1}.** ${t}`).join('\n')
  : draft.x.text;
const discordPayload = {
  embeds: [{
    title: `New Draft: ${typeLabels[draft.contentType] || draft.contentType}`,
    description: `**Topic:** ${draft.topic}`,
    color: 3447003,
    fields: [
      { name: 'LinkedIn', value: draft.linkedin.text.substring(0, 1024) },
      { name: `X ${draft.x.isThread ? '(Thread)' : '(Tweet)'}`, value: xText.substring(0, 1024) },
      { name: 'Actions', value: `[Approve](${approveUrl}) | [Reject](${rejectUrl})` }
    ],
    footer: { text: `Draft ID: ${draft.id} | ${new Date().toLocaleString('en-CA', { timeZone: 'America/Edmonton' })}` }
  }]
};
return [{ json: { discordPayload, discordWebhook: DISCORD_WEBHOOK } }];
